import{a as e,c as t,i as n,l as r,n as i,o as a,r as o,s,t as c}from"./app-F1EwwXV_.js";import"./my-photo-DNrNUHKE.js";var l=JSON.parse(`{"path":"/about.html","title":"About Me","lang":"en-US","frontmatter":{"title":"About Me","contributors":false},"git":{"updatedTime":1774698727000,"changelog":[{"hash":"cff23f05e912c819f2d68ca2eae71192c73adc8e","time":1774698727000,"email":"roufangwang@gmail.com","author":"Ruo-Fang Wang","message":"Change source directory for deployment"}]},"filePathRelative":"about.md"}`),u={name:`about.md`},d={class:`vp-hero-action-button primary`};function f(c,l,u,f,p,m){let h=t(`router-link`),g=t(`DynamicDuration`);return s(),o(`div`,null,[l[15]||=n(`<h1 id="about-me" tabindex="-1"><a class="header-anchor" href="#about-me"><span>About Me</span></a></h1><div class="about-me-container"><img src="/myWebPortfolios/images/my-photo.jpg" alt="Ruo-Fang&#39;s photo" class="photo"><div><h3>Ruo-Fang Wang</h3><h3>Front-end / UI / Web Developer</h3></div></div><h2 id="background" tabindex="-1"><a class="header-anchor" href="#background"><span>📋 Background</span></a></h2><p>I am a dedicated <strong>Front-end Engineer</strong> currently at <strong>ViewSonic</strong>, where I specialize in building high-performance desktop applications, web apps, and developing <strong>private UI libraries</strong> using <strong>React, TypeScript, and Material-UI (MUI)</strong>. My work is deeply rooted in creating accessible and inclusive digital experiences, including implementing features that comply with the <strong>European Accessibility Act (EAA)</strong> and ensuring <strong>WCAG standards</strong> are met.</p><p>With a <strong>GPA of 3.95</strong> and Dean’s Honor recognition from <strong>Algonquin College&#39;s Interactive Media Design</strong> program, I bridge the gap between design and technical execution. My professional journey includes serving as a <strong>Student Web Publisher</strong> for the <strong>Government of Canada</strong>, where I automated newsletter templates to improve efficiency by 33%, and a <strong>UI Developer Co-op</strong> at <strong>Agility PR Solutions</strong>, where I focused on revamping reusable components and refining SCSS architectures.</p><p>My background is uniquely multifaceted; before transitioning into engineering, I spent nearly three years as a <strong>Marketing Officer at DBS Bank</strong>, honing my communication and strategic thinking skills. This experience, combined with a <strong>Bachelor of Arts in Economics</strong> from National Taipei University, allows me to approach development with a logical, data-driven perspective and a keen eye for business impact. I am a lifelong learner who even dedicated a <strong>seven-month sabbatical</strong> to an <strong>in-depth study of React</strong>, and I thrive in collaborative <strong>Agile/Scrum</strong> environments where I can deliver scalable, high-quality web solutions.</p>`,6),i(`div`,d,[a(h,{to:`/contact.html`,class:`action-button contact-me`,"aria-label":`Contact Me`},{default:r(()=>[...l[0]||=[e(`Contact Me`,-1)]]),_:1})]),l[16]||=n(`<h2 id="education" tabindex="-1"><a class="header-anchor" href="#education"><span>🎓 Education</span></a></h2><ul><li><p><strong>Algonqion College</strong> - Ottawa, ON, Canada</p><ul><li>Diploma, Interactive Media Design</li><li>Sep 2021 - Aug 2023</li><li>Grade: GPA: 3.95</li><li>Activities and societies: Dean Honor 2021-2023</li><li>Skills: <ul><li>Web Development: HTML, CSS, SCSS, JavaScript, React, Vue, Vite, Git, GitHub</li><li>Design and Media: Adobe Creative Suite</li><li>Content Management Systems (CMS): WordPress, Shopify</li><li>UI/UX: Adobe XD, Figma, Figjam</li></ul></li></ul></li><li><p><strong>National Taipei University</strong> - Taipei, Taiwan</p><ul><li>Bachelor of Arts - BA, Economics</li><li>Sep 2013 - Jun 2017</li><li>Grade: GPA: 3.48</li><li>Activities and societies: President of Zither Club, 2015-2016</li></ul></li></ul><h2 id="skills" tabindex="-1"><a class="header-anchor" href="#skills"><span>💻 Skills</span></a></h2><h3 id="web-development" tabindex="-1"><a class="header-anchor" href="#web-development"><span>Web Development</span></a></h3><ul><li>React</li><li>React Redux</li><li>Redux Toolkit</li><li>JavaScript</li><li>Electron</li><li>Node.js</li><li>HTML</li><li>CSS</li><li>Sass/SCSS</li><li>Vue</li><li>Angular</li><li>TypeScript</li><li>Git &amp; GitHub</li><li>PHP</li><li>Liquid</li></ul><h3 id="uiux-design" tabindex="-1"><a class="header-anchor" href="#uiux-design"><span>UIUX Design</span></a></h3><ul><li>Figma</li><li>Figjam</li><li>Adobe XD</li><li>Adobe Photoshop</li><li>Adobe Illustrator</li></ul><h3 id="content-management-system" tabindex="-1"><a class="header-anchor" href="#content-management-system"><span>Content Management System</span></a></h3><ul><li>WordPress</li><li>Shopify</li><li>Adobe Experience Manager (AEM)</li></ul><h2 id="work-experience-in-taiwan" tabindex="-1"><a class="header-anchor" href="#work-experience-in-taiwan"><span>💼 Work Experience in Taiwan 🇹🇼</span></a></h2><h3 id="front-end-engineer" tabindex="-1"><a class="header-anchor" href="#front-end-engineer"><span>Front-end Engineer</span></a></h3>`,11),i(`ul`,null,[l[2]||=i(`li`,null,`ViewSonic · Permanent Full-time`,-1),i(`li`,null,[l[1]||=e(`Mar 2024 - Present · `,-1),a(g,{from:`2024-03`,lang:`en`})]),l[3]||=i(`li`,null,`New Taipei City, Taiwan`,-1),l[4]||=i(`li`,null,[e(`Job Description: `),i(`ul`,null,[i(`li`,null,`Develop accessibility features for the desktop application to comply with the European Accessibility Act (EAA), and implement new functionalities based on business requirements using Electron, React, React Router, and TypeScript.`),i(`li`,null,`Continuously improve and refactor existing code to reduce package size and enhance performance, aiming to minimize the risk of application crashes.`),i(`li`,null,`Build a private UI library for internal use across multiple projects, featuring reusable components developed with React, TypeScript, customized Material-UI (MUI), and Azure DevOps Artifacts. Document UI specifications with Storybook and deploy static documentation to AWS S3 via Azure DevOps CI/CD pipelines.`),i(`li`,null,`Ensure high-quality UI and branding by customizing MUI themes, components, and typography in alignment with design systems, mockups, and prototypes provided by UI/UX designers.`),i(`li`,null,`Deliver front-end web solutions using React and its ecosystem, including React Router, React Redux, Redux Toolkit, and Material-UI (MUI). Integrate APIs via Axios and manage data interactions using Lodash. Write automated tests for websites using Cypress to ensure code quality and functional reliability.`),i(`li`,null,`Thrive in a fast-paced Scrum environment by collaborating closely with UI/UX designers, back-end developers, project managers, and product development managers. Proactively reprioritize tasks to optimize efficiency throughout Agile sprints.`)])],-1)]),l[17]||=i(`h3`,{id:`marketing-officer`,tabindex:`-1`},[i(`a`,{class:`header-anchor`,href:`#marketing-officer`},[i(`span`,null,`Marketing Officer`)])],-1),i(`ul`,null,[l[6]||=i(`li`,null,`DBS Bank · Permanent Full-time`,-1),i(`li`,null,[l[5]||=e(`Jul 2018 - Apr 2021 · `,-1),a(g,{from:`2018-07`,to:`2021-04`,lang:`en`})]),l[7]||=i(`li`,null,`Taipei City, Taiwan`,-1),l[8]||=i(`li`,null,[e(`Job Description: `),i(`ul`,null,[i(`li`,null,`Orchestrated comprehensive Marketing Strategies spanning branch communications to digital marketing for an array of Consumer banking products. Demonstrated outstanding proficiency by maintaining an impressive CPL of CAD 27 in digital marketing initiatives for mortgage loans.`),i(`li`,null,`Collaborated seamlessly with diverse stakeholders across multiple squad teams, honing and showcasing exemplary leadership and communication skills.`),i(`li`,null,`Strategically designed and executed social media campaigns for Consumer banking products including loans, deposits, and investment offerings.`),i(`li`,null,`Leveraged the resources of DBS Bank (Singapore) to curate and publish 21 articles and videos. Pioneered the launch of bi-weekly and daily newsletters, dedicated to promoting investment products among our esteemed wealth clientele, significantly enhancing brand awareness within this segment.`),i(`li`,null,`Conceptualized, organized, and hosted highly successful webinars focused on unit funds, achieving established product goals within an impressive one-month timeframe.`)])],-1)]),l[18]||=i(`h2`,{id:`work-experience-in-canada`,tabindex:`-1`},[i(`a`,{class:`header-anchor`,href:`#work-experience-in-canada`},[i(`span`,null,`💼 Work Experience in Canada 🇨🇦`)])],-1),l[19]||=i(`h3`,{id:`student-web-publisher`,tabindex:`-1`},[i(`a`,{class:`header-anchor`,href:`#student-web-publisher`},[i(`span`,null,`Student Web Publisher`)])],-1),i(`ul`,null,[l[10]||=i(`li`,null,`Government of Canada · Seasonal`,-1),i(`li`,null,[l[9]||=e(`Jun 2022 - Aug 2023 · `,-1),a(g,{from:`2022-06`,to:`2023-08`,lang:`en`})]),l[11]||=n(`<li>Ottawa, Ontario, Canada · Hybrid</li><li>Job Description: <ul><li>Conducted thorough Quality Assurance checks on web pages to ensure compliance with WCAG standards, maintaining a high level of accessibility.</li><li>Demonstrated proficiency in crafting customized web pages in response to clients&#39; specific requests, utilizing Adobe Experience Manager (AEM) to implement designs effectively.</li><li>Successfully remedied 50 broken links within web pages, ensuring seamless navigation for users, and subsequently published the pages with updated, functional links.</li><li>Streamlined web content by archiving 221 outdated pages through AEM, enhancing the overall user experience.</li><li>Effectively managed the integration of 772 new links into web pages after a migration, ensuring smooth transition and optimal functionality.</li><li>Played a pivotal role in creating and publishing web pages for weekly newsletters, enhancing the template using HTML and CSS codes within AEM text blocks. This streamlined editing, saving 33% of working time and making maintenance more accessible for non-coders.</li><li>Produced insightful web analytics reports using Adobe Analytics, tailored to internal client specifications. Reports included critical metrics such as popular search terms, peak visitation hours, and more, providing valuable insights for strategic decision-making.</li></ul></li><li>Skills: <ul><li>Web Content Accessibility Guidelines (WCAG)</li><li>Adobe Experience Manager (AEM)</li><li>Adobe Analytics (AA)</li><li>HTML</li><li>CSS</li></ul></li>`,3)]),l[20]||=i(`h3`,{id:`ui-developer-co-op`,tabindex:`-1`},[i(`a`,{class:`header-anchor`,href:`#ui-developer-co-op`},[i(`span`,null,`UI Developer Co-op`)])],-1),i(`ul`,null,[l[13]||=i(`li`,null,`Agility PR Solutions · Co-op`,-1),i(`li`,null,[l[12]||=e(`Jan 2023 - Apr 2023 · `,-1),a(g,{from:`2023-01`,to:`2023-04`,lang:`en`})]),l[14]||=n(`<li>Ottawa, Ontario, Canada · Remote</li><li>Job Description: <ul><li>Proficiently addressed UI discrepancies, utilizing a skill set encompassing HTML, SCSS, JavaScript, and fundamental Angular. Meticulously adjusted SCSS codes for components to align precisely with mock-up designs, ensuring a seamless user experience.</li><li>Revamped 7 general components like checkboxes, radio buttons, input fields, text areas, selections, various buttons, and sidebar across multiple product pages, aligning them with new mock-ups. Employing a comprehensive toolkit featuring HTML, SCSS, JavaScript, Angular, and Typescript, the components were seamlessly integrated with the refreshed design.</li><li>Demonstrated a keen eye for style by systematically updating the SCSS stylesheet and variables in accordance with new mock-ups, refining attention to detail in the design process.</li><li>Skillfully navigated the Jira framework and adeptly executed tasks within the Agile/Scrum development process. Demonstrated exceptional time management and collaborative skills within the dynamic front-end team, consistently meeting deadlines and fostering a culture of teamwork.</li></ul></li><li>Skills: <ul><li>TypeScript</li><li>Angular</li><li>Front-End Development</li><li>Sass (SCSS)</li><li>Agile(Scrum) Development Process</li></ul></li>`,3)])])}var p=c(u,[[`render`,f]]);export{l as _pageData,p as default};